+// getChildIDs extracts IDs from a slice of steps (helper for tests).
+func getChildIDs(steps []*Step) []string {
+	ids := make([]string, len(steps))
+	for i, s := range steps {
+		ids[i] = s.ID
+	}
+	return ids
+}
